using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI MAXN=3e4+5;
int f[MAXN],sz[MAXN],d[MAXN];
int find(int x)
{
	if(f[x]==x)return x;
	int t=find(f[x]);
	d[x]+=d[f[x]];
	return f[x]=t;
}
signed main()
{
	FOR(i,1,3e4)f[i]=i,sz[i]=1;
	int n=read();
	while(n--)
	{
		char c;int x,y;
		cin>>c>>x>>y;
		int fx=find(x),fy=find(y);
		if(c=='M')
		{
			d[fx]+=sz[fy];
			f[fx]=fy;
			sz[fy]+=sz[fx];
			sz[fx]=0;
		}
		else
		{
			if(find(x)!=find(y))NoAns
			else writeln(abs(d[y]-d[x])-1);
		}
	}
	return false;
}
